{
  "mode": "method",
  "tests": [
    {
      "name": "valid_user_login",
      "input": {
        "username": "validUser",
        "password": "validPassword"
      },
      "output": {
        "status": "success",
        "token": "validToken123"
      },
      "notes": "Tests successful login with valid credentials."
    },
    {
      "name": "invalid_user_login",
      "input": {
        "username": "invalidUser",
        "password": "invalidPassword"
      },
      "output": {
        "status": "error",
        "message": "Invalid username or password."
      },
      "notes": "Tests login failure with invalid credentials."
    },
    {
      "name": "user_role_lookup",
      "input": {
        "userId": 1
      },
      "output": {
        "roles": ["admin", "user"]
      },
      "notes": "Tests retrieval of roles for a valid user."
    },
    {
      "name": "user_role_lookup_nonexistent",
      "input": {
        "userId": 999
      },
      "output": {
        "roles": []
      },
      "notes": "Tests retrieval of roles for a nonexistent user."
    },
    {
      "name": "create_user",
      "input": {
        "username": "newUser",
        "password": "newPassword"
      },
      "output": {
        "status": "success",
        "userId": 2
      },
      "notes": "Tests successful user creation."
    },
    {
      "name": "create_user_duplicate",
      "input": {
        "username": "validUser",
        "password": "anotherPassword"
      },
      "output": {
        "status": "error",
        "message": "Username already exists."
      },
      "notes": "Tests user creation with an existing username."
    },
    {
      "name": "update_user_role",
      "input": {
        "userId": 1,
        "role": "editor"
      },
      "output": {
        "status": "success"
      },
      "notes": "Tests successful update of user role."
    },
    {
      "name": "update_user_role_invalid",
      "input": {
        "userId": 999,
        "role": "editor"
      },
      "output": {
        "status": "error",
        "message": "User not found."
      },
      "notes": "Tests role update for a nonexistent user."
    }
  ],
  "assumptions": "All tests are run against a real PostgreSQL database with pre-migrated data.",
  "notes": "Ensure to log any bugs found during testing."
}
